const registry: Record<string, StyleCartridge> = {};

// Initialize Registry with Defaults
DESIGN_PRESETS.forEach(preset => {
  registry[preset.id] = {
    id: preset.id,
    meta: preset,
    previewConfig: DEFAULT_THEME 
  };
});

// Register Implemented Cartridges
registry['cyberpunk'] = cyberpunk;
