        width: 400px; height: 400px;
        background: radial-gradient(circle, #CCFF00 0%, transparent 60%);
        mix-blend-mode: exclusion;
        filter: blur(80px);
        animation: acid-pulse 5s infinite alternate;
        z-index: -1;
      }

      @keyframes acid-pulse {
        0% { transform: scale(1); opacity: 0.5; }
        100% { transform: scale(1.5); opacity: 0.8; }
      }

      /* Distorted Panels */
      .acid-panel, .ds-panel, .ds-card, .acid-nav {
        background: #000;
        border: 1px solid #555;
        position: relative;
        padding: 20px;
      }

      /* Chrome Text Effect */
      .ds-hero-title {
        font-weight: 700;
        text-transform: uppercase;
        background: linear-gradient(to bottom, #FFF 0%, #888 50%, #000 51%, #FFF 100%);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        font-size: 4rem;
        letter-spacing: -2px;
        transform: scaleY(1.5);
        margin-bottom: 40px;
      }
      .ds-hero-title span {
        color: #CCFF00;
        background: none;
        -webkit-text-fill-color: initial;
        display: block;
